// Pseudo-schema validation for streaming records
function validate(record, schema) {
  const required = schema.required || [];
  const missing = required.filter(k => !(k in record));
  if (missing.length) throw new Error("Missing fields: " + missing.join(", "));
  if (schema.types) {
    for (const [k, t] of Object.entries(schema.types)) {
      if (typeof record[k] !== t) throw new Error("Invalid type for " + k);
    }
  }
  return true;
}
```

