## Code Example
```javascript
// Azure Function to detect encoding and transcode to UTF-8
const fs = require('fs');
module.exports = async function (context, myBlob) {
    const buffer = Buffer.from(myBlob);
    const isUtf16 = buffer[0] === 0xFF && buffer[1] === 0xFE;
    let content;

    if (isUtf16) {
        content = buffer.toString('utf16le');
    } else {
        content = buffer.toString('utf8');
    }

    context.bindings.outputBlob = content;
};
```

